Greedy insertion with route regeneration and fallback empty assign creation per order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		valid     bool
	}
	ordersCount := len(oris)
	for oi := 0; oi < ordersCount; oi++ {
		bestCandidate := candidate{valid: false, costDelta: 1e100}
		savedStates := make([]float64, dispatch.AssignsLen)
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			savedStates[ai] = dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				delta := newCost - savedStates[ai]
				if delta >= 0 && (delta < bestCandidate.costDelta || !bestCandidate.valid) {
					bestCandidate.assignIdx = ai
					bestCandidate.costDelta = delta
					bestCandidate.valid = true
				}
			}
			dispatch.Assigns[ai].RemoveShip(total_ship + oi)
			dispatch.Assigns[ai].GenRoute()
		}
		if bestCandidate.valid {
			dispatch.Assigns[bestCandidate.assignIdx].AddShip(total_ship+oi, oris[oi], dess[oi])
			dispatch.Assigns[bestCandidate.assignIdx].GenRoute()
		} else {
			fallbackCreated := false
			for ai := 0; ai < MAXASSIGNS; ai++ {
				if ai < dispatch.AssignsLen {
					ok := dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi])
					if ok {
						dispatch.Assigns[ai].GenRoute()
						fallbackCreated = true
						break
					}
				} else {
					if dispatch.AssignsLen < MAXASSIGNS {
						idx := dispatch.AssignsLen
						dispatch.Assigns[idx].AddShip(total_ship+oi, oris[oi], dess[oi])
						dispatch.Assigns[idx].GenRoute()
						dispatch.AssignsLen++
						fallbackCreated = true
						break
					}
				}
			}
			if !fallbackCreated && dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				dispatch.Assigns[idx].AddShip(total_ship+oi, oris[oi], dess[oi])
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

